import{c as n}from"./app.8935f5f1.js";const s={},o=n('<h3 id="阿里云镜像加速" tabindex="-1"><a class="header-anchor" href="#阿里云镜像加速" aria-hidden="true">#</a> 阿里云镜像加速</h3><ul><li><ol><li>安装／升级Docker客户端<br> 推荐安装1.10.0以上版本的Docker客户端，参考文档 docker-ce</li></ol></li><li><ol start="2"><li>配置镜像加速器 针对Docker客户端版本大于 1.10.0 的用户 您可以通过修改daemon配置文件/etc/docker/daemon.json来使用加速器</li></ol></li></ul><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">mkdir</span> -p /etc/docker\n<span class="token function">sudo</span> <span class="token function">tee</span> /etc/docker/daemon.json <span class="token operator">&lt;&lt;-</span><span class="token string">&#39;EOF&#39;\n{\n  &quot;registry-mirrors&quot;: [&quot;https://2jns9a72.mirror.aliyuncs.com&quot;]\n}\nEOF</span>\n<span class="token function">sudo</span> systemctl daemon-reload\n<span class="token function">sudo</span> systemctl restart docker\n</code></pre></div><ul><li>CentOS</li><li>Mac</li><li>Windows</li></ul><ol><li>安装／升级Docker客户端 推荐安装1.10.0以上版本的Docker客户端，参考文档 docker-ce</li><li>配置镜像加速器 针对Docker客户端版本大于 1.10.0 的用户 您可以通过修改daemon配置文件/etc/docker/daemon.json来使用加速器</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">mkdir</span> -p /etc/docker\n<span class="token function">sudo</span> <span class="token function">tee</span> /etc/docker/daemon.json <span class="token operator">&lt;&lt;-</span><span class="token string">&#39;EOF&#39;\n{\n  &quot;registry-mirrors&quot;: [&quot;https://2jns9a72.mirror.aliyuncs.com&quot;]\n}\nEOF</span>\n<span class="token function">sudo</span> systemctl daemon-reload\n<span class="token function">sudo</span> systemctl restart docker\n</code></pre></div>',6);s.render=function(n,s){return o};export{s as default};
